def parse_monto(raw: str):
    try:
        n = int(raw.strip())
    except ValueError:
        return False, None, "no es entero"
    if n < 0:
        return False, None, "fuera de dominio (negativo)"
    return True, n, None

for v in ["10", "0", "-3", "abc"]:
    print(v, "→", parse_monto(v))

