def normalize_email(raw: str) -> str:
    # Opción raise: el caller controla el lote con try/except
    s = raw.strip().lower()
    if not s or "@" not in s:
        raise ValueError(f"email inválido: {raw!r}")
    return s

print("Política: raise ValueError para no devolver estados ambiguos; el lote atrapa por fila.")
for row in ["  Z@W.COM ", "malo", "a@b.com"]:
    try:
        print("OK", normalize_email(row))
    except ValueError as e:
        print("SKIP", e)

