def make_normalizer(mode: str):
    if mode == "digits":
        def digits(s: str) -> str:
            return "".join(ch for ch in s if ch.isdigit())
        return digits
    if mode == "lower":
        def lower(s: str) -> str:
            return s.strip().lower()
        return lower
    raise ValueError("mode desconocido")

print(make_normalizer("digits")("1a2b"))
print(make_normalizer("lower")(" HOLA "))

